BEGIN;

DELETE FROM route_waypoints WHERE route_code = 'PCI2';
DELETE FROM service_routes WHERE route_code = 'PCI2';

VALUES ('PCI2', 'PCI2', 'PCI2 service imported from JRC ECDIS route sheets.', TRUE)
ON CONFLICT (code) DO UPDATE
SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  is_active = TRUE;

VALUES ('PCI2', 'PCI2', 'PCI2 - KRPUS/KRKAN/CNSHA/IDJKT/IDSRG/THLCH/CNSHA/KRPUS', 'ROUND', 'PCI2 full rotation imported from JRC ECDIS route sheets.', TRUE);


COMMIT;
